package com.example.app.waitlist;
import com.example.app.common.BaseEntity; import com.example.app.company.Company; import com.example.app.client.Client; import com.example.app.session.SessionBooking; import com.example.app.session.SessionType; import com.example.app.user.User; import jakarta.persistence.*; import lombok.Getter; import lombok.Setter; import java.time.*;
@Getter @Setter @Entity @Table(name="waitlist_request") public class WaitlistRequest extends BaseEntity { @ManyToOne(optional=false) @JoinColumn(name="company_id") private Company company; @ManyToOne @JoinColumn(name="client_id") private Client client; @Column(name="guest_user_id",length=64) private String guestUserId; @ManyToOne @JoinColumn(name="service_id") private SessionType service; @Column(name="location_id") private Long locationId; @Column(name="target_type",nullable=false,length=32) private String targetType; @ManyToOne @JoinColumn(name="target_session_id") private SessionBooking targetSession; @Column(name="date_from",nullable=false) private LocalDate dateFrom; @Column(name="date_to",nullable=false) private LocalDate dateTo; @Column(name="employee_preference_type",nullable=false,length=32) private String employeePreferenceType="ANY"; @ManyToOne @JoinColumn(name="specific_employee_id") private User specificEmployee; @Column(name="requested_participants",nullable=false) private Integer requestedParticipants=1; @Column(nullable=false,length=32) private String status="ACTIVE"; @Column(nullable=false,length=32) private String source="STAFF"; @Column(length=1000) private String notes; @Column(name="joined_at",nullable=false) private LocalDateTime joinedAt=LocalDateTime.now(); @Column(name="expires_at") private LocalDateTime expiresAt; @ManyToOne @JoinColumn(name="booked_booking_id") private SessionBooking bookedBooking; @Column(name="duplicate_key",length=512) private String duplicateKey; @Version private Long version; }